private boolean isQualifiedNameInferred(String qName, Node n, JSDocInfo info, Node rhsValue, JSType valueType) {
  if (qName == null || valueType == null) {
    return false;
  }

  if (info != null) {
    if (info.hasType() || info.hasEnumParameterType() || (isConstantSymbol(info, n) && valueType != null && !valueType.isUnknownType()) || FunctionTypeBuilder.isFunctionTypeDeclaration(info)) {
      return false;
    }
  }

  if (rhsValue != null && rhsValue.isFunction()) {
    AstFunctionContents contents = getFunctionAnalysisResults(scope.getRootNode());
    if (contents == null || !contents.getEscapedQualifiedNames().contains(qName)) {
      return false;
    }
  }

  return true;
}
